(19, 1, 3, 'KCPL-2 Testing', 'ELECTROPLATING BARREL PLATING UNIT', '\n<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <style>\n    * { margin:0; padding:0; box-sizing:border-box; }\n    body { font-family: Arial, Helvetica, sans-serif; background:#f4f4f4; }\n    .email-wrapper { max-width:794px; margin:0 auto; background:#ffffff; }\n    .email-header { background:#1e3a5f; padding:0; }\n    .email-body { padding:30px 40px; font-size:14px; color:#333; line-height:1.7; }\n    .email-footer { background:#1e3a5f; padding:0; }\n    table { border-collapse:collapse; width:100%; }\n    td, th { border:1px solid #ccc; padding:8px; }\n    img { max-width:100%; height:auto; }\n    a { color:#1e3a5f; }\n    h1,h2,h3 { color:#1e3a5f; }\n    ul, ol { padding-left:20px; }\n    li { margin-bottom:4px; }\n  </style>\n</head>\n<body>\n  <div class=\"email-wrapper\">\n    <div class=\"email-header\">\n      <div style=\"background:#1e3a5f; padding: 30px 40px; border-bottom: 5px solid rgba(0,0,0,0.1);\">\n        <table style=\"width:100%;\" cellpadding=\"0\" cellspacing=\"0\">\n          <tbody><tr>\n            <td style=\"vertical-align: middle;\">\n              <div style=\"font-size: 32px; font-weight: 800; color: #fff; text-transform: uppercase; letter-spacing: 1px;\">\n                Komal Chemiequip Pvt. Ltd.\n              </div>\n              <div style=\"font-size: 14px; color: rgba(255,255,255,0.7); margin-top: 5px; font-style: italic;\">\n                Innovation in Every Step\n              </div>\n            </td>\n            <td style=\"text-align: right; vertical-align: middle;\">\n               <div style=\"background: rgba(255,255,255,0.2); padding: 10px 15px; display: inline-block; border-radius: 4px; border: 1px solid rgba(255,255,255,0.3);\">\n                 <span style=\"font-size: 18px; font-weight: bold; color: #fff;\">EST. 1992</span>\n               </div>\n            </td>\n          </tr>\n        </tbody></table>\n      </div>\n      <div style=\"height: 1px; background: rgba(255,255,255,0.1);\"></div>\n    </div>\n    <div class=\"email-body\">\n\n\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Submersible Plating Barrels</title>\n\n\n\n\n<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n<tbody><tr>\n<td align=\"center\">\n\n<!-- Main Container -->\n<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"max-width:800px; background:#ffffff; margin:20px auto; padding:20px; border-radius:6px; text-align:left; word-break:break-word;\">\n\n<tbody><tr>\n<td style=\"font-size:20px; font-weight:bold; color:#333; padding-bottom:10px;\">\nUpgrade Your Plating Efficiency with Advanced Submersible Barrels\n</td>\n</tr>\n\n<tr>\n<td style=\"font-size:14px; color:#555; line-height:1.6; word-break:break-word;\">\nDear Sir / Madam,<br><br>\nGreetings from <strong>Komal Chemiequip Pvt. Ltd.</strong>.<br><br>\n\nWe are pleased to introduce our <strong>Submersible Plating Barrels</strong>, designed for high productivity, consistent coating quality, and reduced operational costs.\n</td>\n</tr>\n\n<!-- Product Image -->\n<tr>\n<td style=\"padding-top:15px;\">\n<img src=\"https://www.komalchemiequip.com/images/image131.jpg\" alt=\"Submersible Plating Barrel\" style=\"width:100%; max-width:100%; height:auto; border-radius:6px;\">\n</td>\n</tr>\n\n<!-- Overview -->\n<tr>\n<td style=\"padding-top:15px; font-size:14px; color:#555; line-height:1.6; word-break:break-word;\">\nOur fully submerged barrel systems are manufactured using high-quality <strong>PP / Perspex / CPVC materials</strong>, ensuring durability and chemical resistance.\n</td>\n</tr>\n\n<!-- Features -->\n<tr>\n<td style=\"padding-top:15px;\">\n<strong style=\"color:#333;\">Key Features:</strong>\n<ul style=\"font-size:14px; color:#555; line-height:1.6; padding-left:18px; margin:10px 0;\">\n<li>Ideal for bulk plating of small components</li>\n<li>Uniform coating with superior finish</li>\n<li>Geared motor drive system (AC / DC options)</li>\n<li>Reduced labor and operational cost</li>\n<li>Continuous industrial operation capability</li>\n<li>Custom-built designs available</li>\n</ul>\n</td>\n</tr>\n\n<!-- Table -->\n<tr>\n<td style=\"padding-top:10px;\">\n<strong style=\"color:#333;\">Standard Capacity Range:</strong><br><br>\n\n<table width=\"100%\" border=\"1\" cellspacing=\"0\" cellpadding=\"8\" style=\"border-collapse:collapse; font-size:13px; text-align:left; table-layout:fixed; word-break:break-word;\">\n\n<tbody><tr style=\"background:#0073aa; color:#fff;\">\n<th style=\"width:25%;\">Capacity</th>\n<th style=\"width:25%;\">Volume</th>\n<th style=\"width:25%;\">Barrel Size</th>\n<th style=\"width:25%;\">Motor</th>\n</tr>\n\n<tr>\n<td>7 Kg</td>\n<td>205 L</td>\n<td>12\" x 8\"</td>\n<td>0.125 HP</td>\n</tr>\n\n<tr>\n<td>15 Kg</td>\n<td>600 L</td>\n<td>18\" x 10\"</td>\n<td>0.25 HP</td>\n</tr>\n\n<tr>\n<td>20 Kg</td>\n<td>750 L</td>\n<td>24\" x 10\"</td>\n<td>0.25 HP</td>\n</tr>\n\n<tr>\n<td>30 Kg</td>\n<td>900 L</td>\n<td>30\" x 15\"</td>\n<td>0.5 HP</td>\n</tr>\n\n<tr>\n<td>50 Kg</td>\n<td>1200 L</td>\n<td>36\" x 16\"</td>\n<td>1.0 HP</td>\n</tr>\n\n</tbody></table>\n\n</td>\n</tr>\n\n<!-- CTA -->\n<tr>\n<td style=\"padding:25px 0;\">\n<a href=\"https://www.komalchemiequip.com/Submersible%20Plating%20Barrels%20new.htm\" style=\"background:#0073aa; color:#ffffff; padding:12px 25px; text-decoration:none; font-size:14px; border-radius:4px; display:inline-block;\">\nView Product Details\n</a>\n</td>\n</tr>\n\n<!-- Footer -->\n<tr>\n<td style=\"font-size:14px; color:#555; line-height:1.6; word-break:break-word;\">\nWe would be happy to understand your requirement and suggest the right solution for your plating process.\n</td>\n</tr>\n\n</tbody></table>\n\n</td>\n</tr>\n</tbody></table>\n\n\n</div>\n    <div class=\"email-footer