: #ffffff; padding: 10px; border-radius: 12px; box-shadow: 0 8px 25px rgba(0,0,0,0.2);\"><img _ngcontent-ng-c838034683=\"\" src=\"/assets/komal.jpg\" alt=\"Komal Logo\" style=\"height: 65px; display: block;\"></div></td></tr></tbody></table></div><div _ngcontent-ng-c838034683=\"\" style=\"height: 4px; background: rgba(255,255,255,0.05);\"></div></div>\n    <div class=\"email-body\"><meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Submersible Plating Barrels</title>\n\n\n\n\n<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\n<tbody><tr>\n<td align=\"center\">\n\n<!-- Main Container -->\n<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"max-width:800px; background:#ffffff; margin:20px auto; padding:20px; border-radius:6px; text-align:left; word-break:break-word;\">\n\n<tbody><tr>\n<td style=\"font-size:20px; font-weight:bold; color:#333; padding-bottom:10px;\">\nUpgrade Your Plating Efficiency with Advanced Submersible Barrels\n</td>\n</tr>\n\n<tr>\n<td style=\"font-size:14px; color:#555; line-height:1.6; word-break:break-word;\">\nDear Sir / Madam,<br><br>\nGreetings from <strong>Komal Chemiequip Pvt. Ltd.</strong>.<br><br>\n\nWe are pleased to introduce our <strong>Submersible Plating Barrels</strong>, designed for high productivity, consistent coating quality, and reduced operational costs.\n</td>\n</tr>\n\n<!-- Product Image -->\n<tr>\n<td style=\"padding-top:15px;\">\n<img src=\"https://www.komalchemiequip.com/images/image131.jpg\" alt=\"Submersible Plating Barrel\" style=\"width:100%; max-width:100%; height:auto; border-radius:6px;\">\n</td>\n</tr>\n\n<!-- Overview -->\n<tr>\n<td style=\"padding-top:15px; font-size:14px; color:#555; line-height:1.6; word-break:break-word;\">\nOur fully submerged barrel systems are manufactured using high-quality <strong>PP / Perspex / CPVC materials</strong>, ensuring durability and chemical resistance.\n</td>\n</tr>\n\n<!-- Features -->\n<tr>\n<td style=\"padding-top:15px;\">\n<strong style=\"color:#333;\">Key Features:</strong>\n<ul style=\"font-size:14px; color:#555; line-height:1.6; padding-left:18px; margin:10px 0;\">\n<li>Ideal for bulk plating of small components</li>\n<li>Uniform coating with superior finish</li>\n<li>Geared motor drive system (AC / DC options)</li>\n<li>Reduced labor and operational cost</li>\n<li>Continuous industrial operation capability</li>\n<li>Custom-built designs available</li>\n</ul>\n</td>\n</tr>\n\n<!-- Table -->\n<tr>\n<td style=\"padding-top:10px;\">\n<strong style=\"color:#333;\">Standard Capacity Range:</strong><br><br>\n\n<table width=\"100%\" border=\"1\" cellspacing=\"0\" cellpadding=\"8\" style=\"border-collapse:collapse; font-size:13px; text-align:left; table-layout:fixed; word-break:break-word;\">\n\n<tbody><tr style=\"background:#0073aa; color:#fff;\">\n<th style=\"width:25%;\">Capacity</th>\n<th style=\"width:25%;\">Volume</th>\n<th style=\"width:25%;\">Barrel Size</th>\n<th style=\"width:25%;\">Motor</th>\n</tr>\n\n<tr>\n<td>7 Kg</td>\n<td>205 L</td>\n<td>12\" x 8\"</td>\n<td>0.125 HP</td>\n</tr>\n\n<tr>\n<td>15 Kg</td>\n<td>600 L</td>\n<td>18\" x 10\"</td>\n<td>0.25 HP</td>\n</tr>\n\n<tr>\n<td>20 Kg</td>\n<td>750 L</td>\n<td>24\" x 10\"</td>\n<td>0.25 HP</td>\n</tr>\n\n<tr>\n<td>30 Kg</td>\n<td>900 L</td>\n<td>30\" x 15\"</td>\n<td>0.5 HP</td>\n</tr>\n\n<tr>\n<td>50 Kg</td>\n<td>1200 L</td>\n<td>36\" x 16\"</td>\n<td>1.0 HP</td>\n</tr>\n\n</tbody></table>\n\n</td>\n</tr>\n\n<!-- CTA -->\n<tr>\n<td style=\"padding:25px 0;\">\n<a href=\"https://www.komalchemiequip.com/Submersible%20Plating%20Barrels%20new.htm\" style=\"background:#0073aa; color:#ffffff; padding:12px 25px; text-decoration:none; font-size:14px; border-radius:4px; display:inline-block;\">\nView Product Details\n</a>\n</td>\n</tr>\n\n<!-- Footer -->\n<tr>\n<td style=\"font-size:14px; color:#555; line-height:1.6; word-break:break-word;\">\nWe would be happy to understand your requirement and suggest the right solution for your plating process.\n</td>\n</tr>\n\n</tbody></table>\n\n</td>\n</tr>\n</tbody></table></div>\n    <div class=\"email-footer\"><div _ngcontent-ng-c838034683=\"\" style=\"background: #0d0d0d; color: #ffffff; padding: 20px 40px 15px; font-family: \'Inter\', -apple-system, BlinkMacSystemFont, \'Segoe UI\', Roboto, sans-serif;\"><table _ngcontent-ng-c838034683=\"\" cellpadding=\"0\" cellspacing=\"0\" style=\"width: 100%; border-collapse: collapse; margin-bottom: 12px;\"><tbody><tr _ngcontent-ng-c838034683=\"\"><td _ngcontent-ng-c838034683=\"\" style=\"vertical-align: middle;\"><div _ngcontent-ng-c838034683=\"\" style=\"font-size: 18px; font-weight: 800; color: #ffffff; letter-spacing: -0.5px;\">Komal Chemiequip Pvt. Ltd.</div></td><td _ngcontent-ng-c838034683=\"\" style=\"text-align: right; vertical-align: middle;\"><div _ngcontent-ng-c838034683=\"\" style=\"display: inline-block;\"><a _ngcontent-ng-c838034683=\"\" id=\"social-link-fb\" href=\"https://www.facebook.com/\" target=\"_blank\" style=\"text-decoration: none; margin-left: 12px; display: inline-block;\"><div _ngcontent-ng-c838034683=\"\" style=\"width: 28px; height: 28px; background: #1877F2; border-radius: 50%; text-align: center; line-height: 28px; box-shadow: 0 4px 10px rgba(24, 119, 242, 0.3);\"><img _ngcontent-ng-c838034683=\"\" src=\"https://img.icons8.com/ios-glyphs/60/ffffff/facebook-f.png\" width=\"16\" height=\"16\" alt=\"FB\" style=\"vertical-align: middle; display: inline-block;\"></div></a><a _ngcontent-ng-c838034683=\"\" id=\"social-link-ig\" href=\"https://www.instagram.com/?hl=en\" target=\"_blank\" style=\"text-decoration: none; margin-left: 12px; display: inline-block;\"><div _ngcontent-ng-c838034683=\"\" style=\"width: 28px; height: 28px; background: radial-gradient(circle at 30% 107%, #fdf497 0%, #fdf497 5%, #fd5949 45%, #d6249f 60%, #285AEB 90%); border-radius: 50%; text-align: center; line-height: 28px; box-shadow: 0 4px 10px rgba(214, 