(25, 2, 5, 'AA TESTING-2', 'High-Performance Electroplating Chemicals', '\n<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <style>\n    * { margin:0; padding:0; box-sizing:border-box; }\n    body { font-family: Arial, Helvetica, sans-serif; background:#f4f4f4; }\n    .email-wrapper { max-width:794px; margin:0 auto; background:#ffffff; }\n    .email-header { \n      background:#e53935; \n      padding:0; \n      -webkit-print-color-adjust: exact; \n      print-color-adjust: exact;\n    }\n    .email-body { padding:30px 40px; font-size:14px; color:#333; line-height:1.7; }\n    .email-footer { \n      background:#e53935; \n      padding:0; \n      -webkit-print-color-adjust: exact; \n      print-color-adjust: exact;\n    }\n    table { border-collapse:collapse; width:100%; }\n    td, th { border:1px solid #ccc; padding:8px; }\n    img { max-width:100%; height:auto; }\n    a { color:#e53935; }\n    h1,h2,h3 { color:#e53935; }\n    ul, ol { padding-left:20px; }\n    li { margin-bottom:4px; }\n  </style>\n</head>\n<body>\n  <div class=\"email-wrapper\">\n    <div class=\"email-header\"><div _ngcontent-ng-c3266544087=\"\" style=\"margin: 0px; padding: 15px 50px; background: rgb(255, 255, 255); border-bottom: 6px solid rgb(229, 57, 53); font-family: &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; print-color-adjust: exact;\"><table _ngcontent-ng-c3266544087=\"\" cellpadding=\"0\" cellspacing=\"0\" style=\"width: 100%; border-collapse: collapse;\"><tbody><tr _ngcontent-ng-c3266544087=\"\"><td _ngcontent-ng-c3266544087=\"\" style=\"vertical-align: middle;\"><div _ngcontent-ng-c3266544087=\"\" style=\"font-size: 26px; font-weight: 900; color: rgb(229, 57, 53); text-transform: uppercase; letter-spacing: 1px; margin-bottom: 12px; line-height: 1.1;\"> Arnav Agencies </div><div _ngcontent-ng-c3266544087=\"\" style=\"display: inline-block; padding: 6px 16px; background: rgb(229, 57, 53); border-radius: 4px; font-size: 11px; color: rgb(255, 255, 255); font-weight: 700; text-transform: uppercase; letter-spacing: 2px; box-shadow: rgba(0, 0, 153, 0.15) 0px 4px 8px;\"> House of Supplies for Metal Finishing &amp; Electroplating Industries </div></td><td _ngcontent-ng-c3266544087=\"\" style=\"text-align: right; vertical-align: middle;\"><div _ngcontent-ng-c3266544087=\"\" style=\"display: inline-block; padding: 12px; background: #ffffff; border-radius: 12px; border: 1px solid #f0f0f0; box-shadow: 0 10px 25px rgba(0,0,0,0.06);\"><img _ngcontent-ng-c3266544087=\"\" style=\"height: 65px; width: auto; max-width: 180px; display: block; object-fit: contain;\" src=\"https://arnavagencies.com/wp-content/uploads/2023/06/AA-logo-1.png\" alt=\"Arnav Agencies Logo\"></div></td></tr></tbody></table></div></div>\n    <div class=\"email-body\"><!-- PREHEADER (IMPORTANT FOR OPEN RATE) -->\n<div style=\"display:none; max-height:0; overflow:hidden;\">\nHigh-performance electroplating chemicals for consistent industrial results.\n</div>\n\n<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\">\n<tbody><tr>\n<td align=\"center\">\n\n<table class=\"container\" width=\"700\" cellpadding=\"0\" cellspacing=\"0\" style=\"border:1px solid #dcdcdc;\">\n\n<!-- HEADER -->\n<tbody><tr>\n<td class=\"padding\" style=\"padding:20px; border-bottom:3px solid #0b3d91;\">\n\n</td>\n</tr>\n\n<!-- HERO TITLE -->\n<tr>\n<td class=\"padding\" style=\"padding:25px 20px 10px;\">\n\n<h1 style=\"margin:0; font-size:22px; color:#0b3d91; line-height:1.4;\">\nHigh-Performance Electroplating Chemicals\n</h1>\n\n<p style=\"margin:8px 0 0; font-size:14px; color:#444;\">\nReliable solutions engineered for consistent production quality.\n</p>\n\n</td>\n</tr>\n\n<!-- BODY -->\n<tr>\n<td class=\"padding\" style=\"padding:10px 20px 20px; font-size:14px; color:#333; line-height:1.6;\">\n\n<p>\nWe supply a complete range of electroplating and metal finishing chemicals designed to improve coating performance, durability, and process efficiency across industries.\n</p>\n\n<!-- PRODUCT GRID -->\n<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:15px; border-collapse:collapse;\">\n\n<tbody><tr>\n<td class=\"two-col\" width=\"50%\" style=\"border:1px solid #ccc; padding:10px;\">\n<strong>Zinc, Nickel &amp; Copper</strong><br>\n<span style=\"font-size:12px; color:#555;\">Stable plating solutions</span>\n</td>\n\n<td class=\"two-col\" width=\"50%\" style=\"border:1px solid #ccc; padding:10px;\">\n<strong>Gold, Silver &amp; Tin</strong><br>\n<span style=\"font-size:12px; color:#555;\">Decorative finishes</span>\n</td>\n</tr>\n\n<tr>\n<td class=\"two-col\" style=\"border:1px solid #ccc; padding:10px;\">\n<strong>Chrome &amp; Electroless Nickel</strong><br>\n<span style=\"font-size:12px; color:#555;\">Advanced coatings</span>\n</td>\n\n<td class=\"two-col\" style=\"border:1px solid #ccc; padding:10px;\">\n<strong>Conversion &amp; Polishing</strong><br>\n<span style=\"font-size:12px; color:#555;\">Surface finishing</span>\n</td>\n</tr>\n\n</tbody></table>\n\n<!-- WHY US -->\n<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:20px;\">\n<tbody><tr>\n<td style=\"padding:15px; border:1px solid #0b3d91;\">\n\n<strong style=\"color:#0b3d91;\">Why Choose Us</strong><br><br>\n\n• Consistent chemical quality<br>\n• Competitive pricing<br>\n• Reliable supply support<br>\n• Industry expertise<br>\n• Wide product availability\n\n</td>\n</tr>\n</tbody></table>\n\n<!-- CTA BUTTON -->\n<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:20px;\">\n<tbody><tr>\n<td align=\"left\">\n\n<a href=\"https://arnavagencies.com/service/chemicals/\" style=\"background:#0b3d91; color:#ffffff; text-decoration:none; padding:12px 20px; display:inline-block; font-size:14px; font-weight:bold;\">\nView Products\n</a>\n\n</td>\n</tr>\n</tbody></table>\n\n<!-- FALLBACK LINK -->\n<p style=\"margin-top:15px; font-size:12px; color:#555;\">\nIf the button does not work, copy and paste this link:<br>\nhttps://arnavagencies.com/service/chemicals/\n</p>\n\n</td>\n</tr>\n\n</tbody></table>\n\n</td>\n</tr>\n</tbody></table>\n\n\n</div>\n    <div class=\"email-footer\"><div _ngcontent-ng-c3266544087=\"\" style=\"background: #0d0d0d; color: #ffffff; padding: 20px 40px 15px; font-family: \'Inter\', -apple-system, BlinkMacSystemFont, \'Segoe UI\', Roboto, sans-serif; -webkit-print-color-adjust: exact; print-color-adjust: exact;\"><table _ngcontent-ng-c3266544087=\"\" cellpadding=\"0\" cellspacing=\"0\" style=\"width: 100%; border-collapse: collapse; margin-bottom: 12px;\"><tbody><tr _ngcontent-ng-c3266544087=\"\"><td _ngcontent-ng-c3266544087=\"\" style=\"vertical-align: middle;\"><div _ngcontent-ng-c3266544087=\"\" style=\"font-size: 18px; font-weight: 800; color: #ffffff; letter-spacing: -0.5px;\">Arnav Agencies</div></td><td _ngcontent-ng-c3266544087=\"\" style=\"text-align: right; vertical-align: middle;\"><div _ngcontent-ng-c3266544087=\"\" style=\"display: inline-block;\"><a _ngcontent-ng-c3266544087=\"\" id=\"social-link-fb\" href=\"#\" target=\"_blank\" style=\"text-decoration: none; margin-left: 12px; display: inline-block;\"><div _ngcontent-ng-c3266544087=\"\" style=\"width: 28px; height: 28px; background: #1877F2; border-radius: 50%; text-align: center; line-height: 28px; box-shadow: 0 4px 10px rgba(24, 119, 242, 0.3);\"><img _ngcontent-ng-c3266544087=\"\" src=\"https://img.icons8.com/ios-glyphs/60/ffffff/facebook-f.png\" width=\"16\" height=\"16\" alt=\"FB\" style=\"vertical-align: middle; display: inline-block;\"></div></a><a _ngcontent-ng-c3266544087=\"\" id=\"social-link-ig\" href=\"#\" target=\"_blank\" style=\"text-decoration: none; margin-left: 12px; display: inline-block;\"><div _ngcontent-ng-c3266544087=\"\" style=\"width: 28px; height: 28px; background: radial-gradient(circle at 30% 107%, #fdf497 0%, #fdf497 5%, #fd5949 45%, #d6249f 60%, #285AEB 90%); border-radius: 50%; text-align: